def get_deps(tokens):
    deps = []
    for i, word in enumerate(tokens):
        if word == "shows":
            # Dependencies for 'shows'
            for j, v in enumerate(tokens):
                if (j != i) and (v in ["acute", "respiratory", "distress"]):
                    deps.append((i, j))
    return deps

tokens = ["patient", "shows", "acute", "respiratory", "distress"]
print(get_deps(tokens))
# Expected output: [(1, 0), (1, 2), (2, 3), (3, 4)]
